class Solution:
    def minimumTime(self, d, r):
        d1, d2 = d
        r1, r2 = r
        T = 0
        while True:
            T += 1
            only1 = only2 = both = 0
            for t in range(1, T + 1):
                a1 = (t % r1 != 0)
                a2 = (t % r2 != 0)
                if a1 and a2:
                    both += 1
                elif a1:
                    only1 += 1
                elif a2:
                    only2 += 1
            if d1 <= only1 + both and d2 <= only2 + both and d1 + d2 <= only1 + only2 + both:
                return T

