class Solution:
    def minimumTime(self, d, r):
        from math import gcd
        d1, d2 = d
        r1, r2 = r
        l = r1 // gcd(r1, r2) * r2
        def ok(T):
            a1 = T - T // r1
            a2 = T - T // r2
            both = T - T // l
            return d1 <= a1 and d2 <= a2 and d1 + d2 <= both
        lo, hi = 1, 4 * (d1 + d2) + 100
        while lo < hi:
            mid = (lo + hi) // 2
            if ok(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

