var minimumTime = function(d, r) {
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    const d1 = BigInt(d[0]), d2 = BigInt(d[1]);
    const r1 = BigInt(r[0]), r2 = BigInt(r[1]);
    const l = r1 / BigInt(gcd(Number(r1), Number(r2))) * r2;
    const ok = (T) => {
        const a1 = T - T / r1;
        const a2 = T - T / r2;
        const both = T - T / l;
        return d1 <= a1 && d2 <= a2 && (d1 + d2) <= both;
    };
    let lo = 1n, hi = 4n * (d1 + d2) + 100n;
    while (lo < hi) {
        const mid = (lo + hi) / 2n;
        if (ok(mid)) hi = mid; else lo = mid + 1n;
    }
    return Number(lo);
};
